def fib(n: int) -> int:
    # Dictionary to store calculated Fibonacci numbers
    memo = {0: 0, 1: 1}

    def helper(x: int) -> int:
        # Check if the value is already in our memo
        if x in memo:
            return memo[x]

        # Recursive step: Calculate and store the result
        memo[x] = helper(x - 1) + helper(x - 2)
        return memo[x]

    return helper(n)

# Examples:
print(fib(0))  # Output: 0
print(fib(1))  # Output: 1
